# ── 전체 대화 합치기 및 CSV 저장 ──────────────────────────────────────
def main():
    all_conversations = []

    categories = [
        ("쇼핑/패션", shopping_conversations),
        ("연애/친구", relationship_conversations),
        ("건강/운동", health_conversations),
        ("뉴스/시사", news_conversations),
        ("가족/집", family_conversations),
    ]

    for cat_name, convs in categories:
        assert len(convs) == 100, f"{cat_name} 카테고리: {len(convs)}개 (100개 필요)"
        all_conversations.extend(convs)

    assert len(all_conversations) == 500, f"전체 대화 수: {len(all_conversations)} (500개 필요)"

    # CSV 저장
    output_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "normal_conversations_2.csv")

    with open(output_path, "w", newline="", encoding="utf-8-sig") as f:
        writer = csv.writer(f)
        writer.writerow(["idx", "class", "conversation"])

        for i, conv in enumerate(all_conversations):
            idx = f"n_{i + 500:04d}"
            writer.writerow([idx, "일반 대화", conv])

    print(f"[완료] {len(all_conversations)}개 대화 저장됨 → {output_path}")

    # 카테고리별 통계
    print("\n[카테고리별 통계]")
    for cat_name, convs in categories:
        lengths = [len(c) for c in convs]
        avg_len = sum(lengths) / len(lengths)
        min_len = min(lengths)
        max_len = max(lengths)
        in_range = sum(1 for l in lengths if 100 <= l <= 400)
        print(f"  {cat_name}: {len(convs)}개 | 평균 {avg_len:.0f}자 | 최소 {min_len}자 | 최대 {max_len}자 | 100~400자: {in_range}개")

    # 전체 통계
    all_lengths = [len(c) for c in all_conversations]
    in_range_total = sum(1 for l in all_lengths if 100 <= l <= 400)
    print(f"\n  [전체] 평균 {sum(all_lengths)/len(all_lengths):.0f}자 | 최소 {min(all_lengths)}자 | 최대 {max(all_lengths)}자 | 100~400자: {in_range_total}/500")

    # 금칙어 검사
    print("\n[금칙어 검사]")
    forbidden = ["죽", "죽여", "칼", "살려", "내놔", "찐따", "왕따"]
    found_issues = False
    for i, conv in enumerate(all_conversations):
        for word in forbidden:
            if word in conv:
                pos = conv.index(word)
                context = conv[max(0,pos-5):pos+10]
                print(f"  경고 n_{i+500:04d}: '{word}' 발견 → ...{context}...")
                found_issues = True
    if not found_issues:
        print("  금칙어 없음 ✓")


if __name__ == "__main__":
    main()
